import React, { useEffect, useState } from "react";
import axios from "axios";
import './Home.css';

function MyPredictionHistory() {
  const [history, setHistory] = useState([]);
  const [total, setTotal] = useState(0);

  useEffect(() => {
    const user = JSON.parse(localStorage.getItem("user"));

    if (!user) return;

    // 🔥 Fetch history
    axios
      .get(`http://localhost:5001/history/${user.email}`)
      .then((res) => {
        setHistory(res.data);
        setTotal(res.data.length);
      })
      .catch((err) => console.log(err));
  }, []);

  return (
    <div className="history">
    <div style={{ padding: "20px" }}>
      <h2>My Prediction History</h2>

      <p><b>Total Predictions:</b> {total}</p>

      <h3>Recent Predictions</h3>
      </div>
      <table border="1" cellPadding="10" style={{ width: "100%" }}>
        <thead>
          <tr>
            <th>Date</th>
            <th>Role</th>
            <th>Experience</th>
            <th>Salary</th>
          </tr>
        </thead>

        <tbody>
          {history.slice(0, 5).map((item, index) => (
            <tr key={index}>
              <td>{new Date(item.createdAt).toLocaleDateString()}</td>
              <td>{item.JobRole}</td>
              <td>{item.Experience} yrs</td>
              <td>₹ {item.salary}</td>
            </tr>
          ))}
        </tbody>
      </table>

      <br />

      <button onClick={() => window.location.href = "/full-history"}>
        View Full History
      </button>
    </div>
  );
}

export default MyPredictionHistory;
